mapper.select:
SELECT s.id, s.student_id AS studentId, st.student_name AS studentName, st.student_no AS studentNo, s.course_id AS courseId, c.course_no AS courseNo, c.name AS courseName, c.credit, c.hours, c.semester, c.study_nature AS studyNature, t.teacher_name AS teacherName, s.score, s.usual_score AS usualScore, s.exam_score AS examScore, s.total_score AS totalScore, s.usual_weight AS usualWeight, s.exam_weight AS examWeight, s.grade, s.comment, DATE_FORMAT(s.update_time, '%Y-%m-%d %H:%i:%s') AS updateTime FROM score s LEFT JOIN course c ON s.course_id = c.id LEFT JOIN student st ON s.student_id = st.id LEFT JOIN teacher t ON c.teacher_id = t.id
AND s.student_id = #{studentId}
AND s.course_id = #{courseId}
AND s.grade = #{grade}
AND c.semester = #{semester}
ORDER BY c.semester DESC, s.update_time DESC
